import * as fs from 'fs/promises';
import * as path from 'path';
import { Readable } from 'stream';
import { StorageAdapter, UploadParams } from './storage.interface';

export class FilesystemStorageAdapter implements StorageAdapter {
  private uploadDir: string;

  constructor() {
    this.uploadDir = process.env.UPLOAD_DIR || path.join(process.cwd(), 'uploads');
  }

  private async ensureUploadDir(): Promise<string> {
    await fs.mkdir(this.uploadDir, { recursive: true });
    return this.uploadDir;
  }

  async upload(params: UploadParams): Promise<void> {
    const { key, body, contentType: _ } = params;
    const fullPath = path.join(this.uploadDir, key);
    await fs.mkdir(path.dirname(fullPath), { recursive: true });
    await fs.writeFile(fullPath, body);
  }

  async delete(key: string): Promise<void> {
    const fullPath = path.join(this.uploadDir, key);
    try {
      await fs.unlink(fullPath);
    } catch {
      // Idempotent: ignore if file doesn't exist
    }
  }

  async getStream(key: string): Promise<Readable> {
    const fullPath = path.join(this.uploadDir, key);
    try {
      await fs.access(fullPath);
    } catch {
      throw new Error('Archivo no encontrado en almacenamiento');
    }
    const { createReadStream } = await import('fs');
    return createReadStream(fullPath);
  }
}

import {
  BadRequestException,
  Injectable,
  UnauthorizedException,
} from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import * as bcrypt from 'bcrypt';
import * as crypto from 'crypto';
import { Role } from '@prisma/client';
import { PrismaService } from '../prisma/prisma.service';
import { AuditService } from '../audit/audit.service';
import { ClubMembersService } from '../club-members/club-members.service';
import { EmailService } from './email.service';
import { UsersService } from '../users/users.service';
import { User } from '@prisma/client';

@Injectable()
export class AuthService {
  private static readonly RESET_TOKEN_EXPIRY_HOURS = 1;

  constructor(
    private readonly usersService: UsersService,
    private readonly jwtService: JwtService,
    private readonly auditService: AuditService,
    private readonly clubMembersService: ClubMembersService,
    private readonly emailService: EmailService,
    private readonly prisma: PrismaService,
  ) {}

  async validateUser(email: string, password: string): Promise<User | null> {
    const user = await this.usersService.findByEmail(email);
    if (!user) return null;
    const ok = await bcrypt.compare(password, user.passwordHash);
    return ok ? user : null;
  }

  async login(email: string, password: string) {
    try {
      const user = await this.validateUser(email, password);
      if (!user) {
        await this.auditService.log({
          entityType: 'auth',
          action: 'auth.login.failed',
          metadata: { attemptedEmail: email },
        });
        throw new UnauthorizedException('Credenciales inválidas');
      }
      await this.auditService.log({
        entityType: 'auth',
        action: 'auth.login.success',
        actorUserId: user.id,
        entityId: user.id,
      });
      const payload = { sub: user.id, email: user.email, role: user.role };
      const access_token = this.jwtService.sign(payload);
      return {
        access_token,
        user: {
          id: user.id,
          fullName: user.fullName,
          email: user.email,
          role: user.role,
        },
      };
    } catch (error) {
      if (error instanceof UnauthorizedException) {
        throw error;
      }
      const message =
        error && typeof error === 'object' && 'message' in error && typeof (error as any).message === 'string'
          ? (error as any).message
          : 'Error desconocido';
      await this.auditService.log({
        entityType: 'auth',
        action: 'auth.login.error',
        metadata: {
          attemptedEmail: email,
          errorMessage: message,
        },
      });
      throw new UnauthorizedException(`Error al iniciar sesión: ${message}`);
    }
  }

  async register(fullName: string, email: string, password: string) {
    const passwordHash = await bcrypt.hash(password, 10);
    const user = await this.usersService.create({
      fullName,
      email,
      passwordHash,
      role: Role.PARTICIPANT,
    });
    await this.clubMembersService.linkMembersToUser(user.id, user.email);
    await this.auditService.log({
      entityType: 'auth',
      action: 'auth.register.success',
      actorUserId: user.id,
      entityId: user.id,
    });
    const payload = { sub: user.id, email: user.email, role: user.role };
    const access_token = this.jwtService.sign(payload);
    return {
      access_token,
      user: {
        id: user.id,
        fullName: user.fullName,
        email: user.email,
        role: user.role,
      },
    };
  }

  async getMe(userId: string) {
    const now = new Date();
    const user = await this.prisma.user.findUnique({
      where: { id: userId, isActive: true },
      select: {
        id: true,
        fullName: true,
        email: true,
        role: true,
        memberships: {
          where: {
            OR: [{ activeUntil: null }, { activeUntil: { gt: now } }],
          },
          select: {
            clubId: true,
            title: true,
            isPresident: true,
            club: {
              select: { id: true, name: true, code: true },
            },
          },
        },
      },
    });
    if (!user) throw new UnauthorizedException();
    return {
      user: {
        id: user.id,
        fullName: user.fullName,
        email: user.email,
        role: user.role,
        memberships: user.memberships.map((m) => ({
          clubId: m.clubId,
          clubName: m.club.name,
          clubCode: m.club.code,
          title: m.title,
          isPresident: m.isPresident,
        })),
      },
    };
  }

  async forgotPassword(email: string): Promise<{ message: string }> {
    const normalizedEmail = email.trim().toLowerCase();
    const user = await this.prisma.user.findUnique({
      where: { email: normalizedEmail, isActive: true },
    });
    if (user) {
      const rawToken = crypto.randomBytes(32).toString('hex');
      const tokenHash = await bcrypt.hash(rawToken, 10);
      const expiresAt = new Date();
      expiresAt.setHours(expiresAt.getHours() + AuthService.RESET_TOKEN_EXPIRY_HOURS);
      await this.prisma.passwordResetToken.create({
        data: {
          userId: user.id,
          tokenHash,
          expiresAt,
        },
      });
      await this.emailService.sendPasswordResetEmail(user.email, rawToken);
      await this.auditService.log({
        entityType: 'auth',
        action: 'auth.password.reset.requested',
        actorUserId: user.id,
        entityId: user.id,
      });
    }
    return {
      message:
        'Si el correo existe en el sistema, recibirás instrucciones para restablecer tu contraseña.',
    };
  }

  async resetPassword(token: string, newPassword: string) {
    const tokens = await this.prisma.passwordResetToken.findMany({
      where: { usedAt: null, expiresAt: { gt: new Date() } },
      include: { user: true },
    });
    let validToken = null;
    for (const t of tokens) {
      if (await bcrypt.compare(token, t.tokenHash)) {
        validToken = t;
        break;
      }
    }
    if (!validToken) {
      await this.auditService.log({
        entityType: 'auth',
        action: 'auth.password.reset.failed',
        metadata: { reason: 'invalid_or_expired_token' },
      });
      throw new BadRequestException('El enlace de restablecimiento no es válido o ha expirado.');
    }
    const passwordHash = await bcrypt.hash(newPassword, 10);
    await this.prisma.$transaction(async (tx) => {
      await tx.user.update({
        where: { id: validToken.userId },
        data: { passwordHash },
      });
      await tx.passwordResetToken.update({
        where: { id: validToken.id },
        data: { usedAt: new Date() },
      });
    });
    await this.auditService.log({
      entityType: 'auth',
      action: 'auth.password.reset.success',
      actorUserId: validToken.userId,
      entityId: validToken.userId,
    });
    return { message: 'Contraseña restablecida correctamente. Ya podés iniciar sesión.' };
  }

  async updateMe(
    userId: string,
    data: { fullName?: string; email?: string },
  ) {
    const user = await this.usersService.updateMe(userId, data);
    const shouldSync = data.fullName !== undefined || data.email !== undefined;
    if (shouldSync) {
      await this.clubMembersService.syncMemberDataFromUser(
        userId,
        user.fullName,
        user.email,
      );
    }
    await this.auditService.log({
      entityType: 'auth',
      action: 'auth.profile.updated',
      actorUserId: userId,
      entityId: userId,
      metadata: {
        fields: Object.keys(data).filter((k) => data[k as keyof typeof data] !== undefined),
      },
    });
    return { user };
  }

  async changePassword(userId: string, currentPassword: string, newPassword: string) {
    const user = await this.prisma.user.findUnique({
      where: { id: userId, isActive: true },
    });
    if (!user) throw new UnauthorizedException();
    const ok = await bcrypt.compare(currentPassword, user.passwordHash);
    if (!ok) {
      await this.auditService.log({
        entityType: 'auth',
        action: 'auth.password.change.failed',
        actorUserId: userId,
        entityId: userId,
        metadata: { reason: 'wrong_current_password' },
      });
      throw new UnauthorizedException('Contraseña actual incorrecta');
    }
    const passwordHash = await bcrypt.hash(newPassword, 10);
    await this.prisma.user.update({
      where: { id: userId },
      data: { passwordHash },
    });
    await this.auditService.log({
      entityType: 'auth',
      action: 'auth.password.changed',
      actorUserId: userId,
      entityId: userId,
    });
    return { message: 'Contraseña actualizada correctamente.' };
  }
}

import {
  BadRequestException,
  Controller,
  Delete,
  Get,
  Patch,
  Post,
  Body,
  Param,
  Query,
  Req,
  UploadedFile,
  UseGuards,
  UseInterceptors,
  UsePipes,
  ValidationPipe,
} from '@nestjs/common';
import { FileInterceptor } from '@nestjs/platform-express';
import { AuthGuard } from '@nestjs/passport';
import { ClubMemberGuard } from '../club/guards/club-member.guard';
import { ClubAuthorityGuard } from '../club/guards/club-authority.guard';
import { ClubPresidentGuard } from '../club/guards/club-president.guard';
import { ClubReportsService } from './club-reports.service';
import { AttachmentsService } from '../attachments/attachments.service';
import { CreateClubReportDto } from './dto/create-club-report.dto';
import { UpdateClubReportDto } from './dto/update-club-report.dto';
import { QueryClubReportsDto } from './dto/query-club-reports.dto';
import {
  CurrentUser,
  CurrentUserPayload,
} from '../auth/decorators/current-user.decorator';

@Controller('club/reports')
@UseGuards(AuthGuard('jwt'), ClubMemberGuard)
export class ClubReportsController {
  constructor(
    private readonly clubReportsService: ClubReportsService,
    private readonly attachmentsService: AttachmentsService,
  ) {}

  @Get()
  @UseGuards(ClubAuthorityGuard)
  @UsePipes(new ValidationPipe({ transform: true, whitelist: true }))
  findAll(
    @Req() req: { clubId: string },
    @Query() query: QueryClubReportsDto,
  ) {
    return this.clubReportsService.findAll(req.clubId, query);
  }

  @Get(':id')
  @UseGuards(ClubAuthorityGuard)
  findOne(@Param('id') id: string, @Req() req: { clubId: string }) {
    return this.clubReportsService.findOne(id, req.clubId);
  }

  @Post()
  @UseGuards(ClubAuthorityGuard)
  @UsePipes(new ValidationPipe({ whitelist: true }))
  create(
    @CurrentUser() user: CurrentUserPayload,
    @Body() dto: CreateClubReportDto,
    @Req() req: { clubId: string },
  ) {
    return this.clubReportsService.create(req.clubId, dto, user.id);
  }

  @Patch(':id')
  @UseGuards(ClubAuthorityGuard)
  @UsePipes(new ValidationPipe({ whitelist: true }))
  update(
    @Param('id') id: string,
    @Body() dto: UpdateClubReportDto,
    @Req() req: { clubId: string },
  ) {
    return this.clubReportsService.update(id, req.clubId, dto);
  }

  @Post(':id/submit')
  @UseGuards(ClubPresidentGuard)
  submit(
    @CurrentUser() user: CurrentUserPayload,
    @Param('id') id: string,
    @Req() req: { clubId: string },
  ) {
    return this.clubReportsService.submit(id, req.clubId, user.id);
  }

  @Get(':id/attachments')
  @UseGuards(ClubAuthorityGuard)
  listAttachments(@Param('id') id: string, @Req() req: { clubId: string }) {
    return this.attachmentsService.list('report', id);
  }

  @Post(':id/attachments')
  @UseGuards(ClubAuthorityGuard)
  @UseInterceptors(FileInterceptor('file'))
  async uploadAttachment(
    @Param('id') id: string,
    @Req() req: { clubId: string; user: { id: string } },
    @UploadedFile() file: Express.Multer.File,
  ) {
    if (!file) {
      throw new BadRequestException('Archivo requerido (campo "file")');
    }
    return this.attachmentsService.upload('report', id, file, req.user.id, {
      clubId: req.clubId,
    });
  }

  @Delete(':id/attachments/:attachmentId')
  @UseGuards(ClubAuthorityGuard)
  deleteAttachment(
    @Param('id') reportId: string,
    @Param('attachmentId') attachmentId: string,
    @Req() req: { clubId: string },
    @CurrentUser() user: CurrentUserPayload,
  ) {
    return this.attachmentsService.delete(attachmentId, {
      clubId: req.clubId,
      actorUserId: user.id,
    });
  }

  @Post(':id/resubmit')
  @UseGuards(ClubPresidentGuard)
  resubmit(
    @CurrentUser() user: CurrentUserPayload,
    @Param('id') id: string,
    @Req() req: { clubId: string },
  ) {
    return this.clubReportsService.resubmit(id, req.clubId, user.id);
  }
}

import {
  Injectable,
  NotFoundException,
  ForbiddenException,
  ConflictException,
} from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { ReportStatus, ReportType } from '@prisma/client';
import { CreateClubReportDto } from './dto/create-club-report.dto';
import { UpdateClubReportDto } from './dto/update-club-report.dto';
import { QueryClubReportsDto } from './dto/query-club-reports.dto';

@Injectable()
export class ClubReportsService {
  constructor(private readonly prisma: PrismaService) {}

  async findAll(clubId: string, query: QueryClubReportsDto) {
    const { periodId, type, status, page = '1', limit = '20' } = query;
    const skip =
      (Math.max(1, parseInt(page, 10)) - 1) *
      Math.min(100, Math.max(1, parseInt(limit, 10)));
    const take = Math.min(100, Math.max(1, parseInt(limit, 10)));

    const where: Record<string, unknown> = { clubId };
    if (periodId) where.districtPeriodId = periodId;
    if (type) where.type = type;
    if (status) where.status = status;

    const [items, total] = await Promise.all([
      this.prisma.report.findMany({
        where,
        skip,
        take,
        orderBy: [{ submittedAt: 'desc' }, { createdAt: 'desc' }],
        include: {
          districtPeriod: {
            select: { id: true, name: true, startDate: true, endDate: true },
          },
        },
      }),
      this.prisma.report.count({ where }),
    ]);

    return { items, total, page: parseInt(page, 10), limit: take };
  }

  async findOne(id: string, clubId: string) {
    const report = await this.prisma.report.findUnique({
      where: { id },
      include: {
        club: { select: { id: true, name: true, code: true } },
        districtPeriod: { select: { id: true, name: true, startDate: true, endDate: true } },
        reviewer: { select: { id: true, fullName: true } },
      },
    });
    if (!report) throw new NotFoundException('Informe no encontrado');
    if (report.clubId !== clubId) {
      throw new ForbiddenException('No pertenece a su club');
    }
    return report;
  }

  async create(
    clubId: string,
    dto: CreateClubReportDto,
    userId: string,
  ) {
    const period = await this.prisma.districtPeriod.findUnique({
      where: { id: dto.districtPeriodId },
    });
    if (!period) throw new NotFoundException('Período no encontrado');

    const existing = await this.prisma.report.findUnique({
      where: {
        clubId_districtPeriodId_type: {
          clubId,
          districtPeriodId: dto.districtPeriodId,
          type: dto.type,
        },
      },
    });
    if (existing) {
      throw new ConflictException(
        'Ya existe un informe para este período y tipo',
      );
    }

    const report = await this.prisma.report.create({
      data: {
        clubId,
        districtPeriodId: dto.districtPeriodId,
        type: dto.type,
        contentJson: dto.contentJson,
        status: ReportStatus.DRAFT,
      },
      include: {
        districtPeriod: { select: { id: true, name: true } },
      },
    });

    await this.prisma.auditLog.create({
      data: {
        clubId,
        actorUserId: userId,
        action: 'report.created',
        entityType: 'Report',
        entityId: report.id,
        metadataJson: JSON.stringify({ periodId: dto.districtPeriodId, type: dto.type }),
      },
    });

    return report;
  }

  async update(
    id: string,
    clubId: string,
    dto: UpdateClubReportDto,
  ) {
    const report = await this.prisma.report.findUnique({
      where: { id },
    });
    if (!report) throw new NotFoundException('Informe no encontrado');
    if (report.clubId !== clubId) {
      throw new ForbiddenException('No pertenece a su club');
    }

    if (report.status === ReportStatus.DRAFT) {
      return this.prisma.report.update({
        where: { id },
        data: {
          ...(dto.contentJson !== undefined && { contentJson: dto.contentJson }),
        },
        include: {
          districtPeriod: { select: { id: true, name: true } },
        },
      });
    }

    if (
      report.status === ReportStatus.OBSERVED ||
      report.status === ReportStatus.REJECTED
    ) {
      return this.prisma.report.update({
        where: { id },
        data: {
          ...(dto.contentJson !== undefined && { contentJson: dto.contentJson }),
          ...(dto.responseToObservations !== undefined && {
            responseToObservations: dto.responseToObservations,
          }),
        },
        include: {
          districtPeriod: { select: { id: true, name: true } },
        },
      });
    }

    throw new ForbiddenException('No se puede editar este informe');
  }

  async submit(id: string, clubId: string, userId: string) {
    const report = await this.prisma.report.findUnique({
      where: { id },
    });
    if (!report) throw new NotFoundException('Informe no encontrado');
    if (report.clubId !== clubId) {
      throw new ForbiddenException('No pertenece a su club');
    }
    if (report.status !== ReportStatus.DRAFT) {
      throw new ForbiddenException('Solo se puede enviar un borrador');
    }

    const updated = await this.prisma.report.update({
      where: { id },
      data: {
        status: ReportStatus.SUBMITTED,
        submittedAt: new Date(),
      },
      include: {
        districtPeriod: { select: { id: true, name: true } },
      },
    });

    await this.prisma.auditLog.create({
      data: {
        clubId,
        actorUserId: userId,
        action: 'report.submitted',
        entityType: 'Report',
        entityId: id,
        metadataJson: JSON.stringify({
          periodId: report.districtPeriodId,
          type: report.type,
        }),
      },
    });

    return updated;
  }

  async resubmit(id: string, clubId: string, userId: string) {
    const report = await this.prisma.report.findUnique({
      where: { id },
    });
    if (!report) throw new NotFoundException('Informe no encontrado');
    if (report.clubId !== clubId) {
      throw new ForbiddenException('No pertenece a su club');
    }
    if (
      report.status !== ReportStatus.OBSERVED &&
      report.status !== ReportStatus.REJECTED
    ) {
      throw new ForbiddenException(
        'Solo se puede reenviar un informe observado o rechazado',
      );
    }

    const updated = await this.prisma.report.update({
      where: { id },
      data: {
        status: ReportStatus.SUBMITTED,
        resubmittedAt: new Date(),
      },
      include: {
        districtPeriod: { select: { id: true, name: true } },
      },
    });

    await this.prisma.auditLog.create({
      data: {
        clubId,
        actorUserId: userId,
        action: 'report.resubmitted',
        entityType: 'Report',
        entityId: id,
        metadataJson: JSON.stringify({
          periodId: report.districtPeriodId,
          type: report.type,
        }),
      },
    });

    return updated;
  }
}

import {
  BadRequestException,
  ConflictException,
  Injectable,
  NotFoundException,
} from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { AuditService } from '../audit/audit.service';
import { CsvParserService } from '../common/bulk/csv-parser.service';
import { BulkImportResult, BulkRowError } from '../common/bulk/bulk-result.types';
import { CreateClubDto } from './dto/create-club.dto';
import { UpdateClubDto } from './dto/update-club.dto';
import { plainToInstance } from 'class-transformer';
import { validate } from 'class-validator';

@Injectable()
export class ClubsService {
  constructor(
    private readonly prisma: PrismaService,
    private readonly audit: AuditService,
    private readonly csvParser: CsvParserService,
  ) {}

  async findAll(includeInactive = false) {
    return this.prisma.club.findMany({
      where: includeInactive ? undefined : { status: 'ACTIVE' },
      orderBy: { name: 'asc' },
    });
  }

  async findOne(id: string) {
    const club = await this.prisma.club.findUnique({
      where: { id },
    });
    if (!club) throw new NotFoundException('Club no encontrado');
    return club;
  }

  async create(dto: CreateClubDto) {
    const existing = await this.prisma.club.findUnique({
      where: { code: dto.code.trim().toUpperCase() },
    });
    if (existing) {
      throw new ConflictException(`Ya existe un club con el código ${dto.code}`);
    }
    return this.prisma.club.create({
      data: {
        name: dto.name.trim(),
        code: dto.code.trim().toUpperCase(),
        presidentEmail: dto.presidentEmail?.trim().toLowerCase() || null,
        enabledForDistrictMeetings: dto.enabledForDistrictMeetings ?? true,
        cuotaAldia: dto.cuotaAldia ?? false,
        informeAlDia: dto.informeAlDia ?? false,
      },
    });
  }

  async update(id: string, dto: UpdateClubDto) {
    await this.findOne(id);
    if (dto.code != null) {
      const existing = await this.prisma.club.findFirst({
        where: { code: dto.code.trim().toUpperCase(), NOT: { id } },
      });
      if (existing) {
        throw new ConflictException(`Ya existe un club con el código ${dto.code}`);
      }
    }
    return this.prisma.club.update({
      where: { id },
      data: {
        ...(dto.name != null && { name: dto.name.trim() }),
        ...(dto.code != null && { code: dto.code.trim().toUpperCase() }),
        ...(dto.presidentEmail !== undefined && {
          presidentEmail: dto.presidentEmail?.trim().toLowerCase() || null,
        }),
        ...(dto.enabledForDistrictMeetings !== undefined && {
          enabledForDistrictMeetings: dto.enabledForDistrictMeetings,
        }),
        ...(dto.cuotaAldia !== undefined && { cuotaAldia: dto.cuotaAldia }),
        ...(dto.informeAlDia !== undefined && { informeAlDia: dto.informeAlDia }),
        ...(dto.status !== undefined && { status: dto.status }),
      },
    });
  }

  async remove(id: string) {
    await this.findOne(id);
    // Baja lógica: se desactiva el club y se evita que participe en nuevas reuniones,
    // pero se conserva el historial de reuniones, eventos, informes y proyectos.
    return this.prisma.club.update({
      where: { id },
      data: {
        status: 'INACTIVE',
        enabledForDistrictMeetings: false,
      },
    });
  }

  getBulkTemplate(): { buffer: Buffer; filename: string } {
    const header = [
      'name',
      'code',
      'presidentEmail',
      'enabledForDistrictMeetings',
      'cuotaAldia',
      'informeAlDia',
    ];
    const example = [
      'Club Rotaract Alpha',
      'CLUB-ALPHA',
      'presi@alpha.org',
      'true',
      'false',
      'false',
    ];
    const buffer = this.csvParser.generateTemplateCsv(header, example);
    return { buffer, filename: 'plantilla-clubes.csv' };
  }

  async bulkImport(
    file: Express.Multer.File | undefined,
    actorUserId: string,
    mode: 'partial' | 'strict' = 'partial',
  ): Promise<BulkImportResult> {
    if (!file?.buffer) {
      throw new BadRequestException('Archivo CSV requerido');
    }

    const rows = this.csvParser.parse(file.buffer);
    const result: BulkImportResult = {
      total: rows.length,
      created: 0,
      failed: 0,
      mode,
      createdIds: [],
      errors: [],
    };

    for (let i = 0; i < rows.length; i++) {
      const row = rows[i];
      const rowNum = i + 2;

      const dto = plainToInstance(CreateClubDto, {
        name: row.name?.trim() || '',
        code: row.code?.trim() || '',
        presidentEmail: row.presidentEmail?.trim() || undefined,
        enabledForDistrictMeetings: this.parseBool(row.enabledForDistrictMeetings, true),
        cuotaAldia: this.parseBool(row.cuotaAldia, false),
        informeAlDia: this.parseBool(row.informeAlDia, false),
      });

      const errors = await validate(dto);
      if (errors.length > 0) {
        const msg = errors.map((e) => Object.values(e.constraints || {}).join(', ')).join('; ');
        result.errors.push({
          row: rowNum,
          data: row as Record<string, unknown>,
          message: msg,
        });
        result.failed++;
        if (mode === 'strict') {
          result.errors.push(
            ...rows.slice(i + 1).map((r, idx) => ({
              row: i + idx + 3,
              data: r as Record<string, unknown>,
              message: 'Importación abortada (modo estricto)',
            })),
          );
          result.failed += rows.length - i - 1;
          return result;
        }
        continue;
      }

      try {
        const existing = await this.prisma.club.findUnique({
          where: { code: (dto as CreateClubDto).code.trim().toUpperCase() },
        });
        if (existing) {
          result.errors.push({
            row: rowNum,
            data: row as Record<string, unknown>,
            message: `Ya existe un club con el código ${(dto as CreateClubDto).code}`,
          });
          result.failed++;
          if (mode === 'strict') {
            return this.abortStrict(result, rows, i + 1, 'Código duplicado');
          }
          continue;
        }

        const club = await this.prisma.club.create({
          data: {
            name: (dto as CreateClubDto).name.trim(),
            code: (dto as CreateClubDto).code.trim().toUpperCase(),
            presidentEmail: (dto as CreateClubDto).presidentEmail?.trim().toLowerCase() || null,
            enabledForDistrictMeetings: (dto as CreateClubDto).enabledForDistrictMeetings ?? true,
            cuotaAldia: (dto as CreateClubDto).cuotaAldia ?? false,
            informeAlDia: (dto as CreateClubDto).informeAlDia ?? false,
          },
        });
        result.created++;
        result.createdIds!.push(club.id);
      } catch (err) {
        const msg = err instanceof Error ? err.message : 'Error desconocido';
        result.errors.push({ row: rowNum, data: row as Record<string, unknown>, message: msg });
        result.failed++;
        if (mode === 'strict') {
          return this.abortStrict(result, rows, i + 1, msg);
        }
      }
    }

    if (result.created > 0) {
      await this.audit.log({
        actorUserId,
        action: 'BULK_IMPORT',
        entityType: 'Club',
        metadata: {
          total: result.total,
          created: result.created,
          failed: result.failed,
        },
      });
    }

    if (result.errors.length > 0) {
      result.reportCsv = this.csvParser.generateReportCsv(
        ['name', 'code', 'presidentEmail', 'enabledForDistrictMeetings', 'cuotaAldia', 'informeAlDia'],
        result.errors,
      );
    }

    return result;
  }

  private parseBool(val: string | undefined, defaultVal: boolean): boolean {
    if (!val || val.trim() === '') return defaultVal;
    const v = val.trim().toLowerCase();
    return v === 'true' || v === '1' || v === 'sí' || v === 'si' || v === 'yes';
  }

  private abortStrict(
    result: BulkImportResult,
    rows: Record<string, string>[],
    fromIdx: number,
    reason: string,
  ): BulkImportResult {
    for (let j = fromIdx; j < rows.length; j++) {
      result.errors.push({
        row: j + 2,
        data: rows[j] as Record<string, unknown>,
        message: `Importación abortada: ${reason}`,
      });
      result.failed++;
    }
    return result;
  }

  async findEnabledForDistrictMeetings() {
    return this.prisma.club.findMany({
      where: { status: 'ACTIVE', enabledForDistrictMeetings: true },
      include: {
        memberships: {
          where: { isPresident: true },
          select: { userId: true },
        },
      },
    });
  }
}

export interface BulkRowError {
  row: number;
  data: Record<string, unknown>;
  message: string;
  field?: string;
}

export interface BulkImportResult<T = unknown> {
  total: number;
  created: number;
  failed: number;
  mode: 'partial' | 'strict';
  createdIds?: string[];
  errors: BulkRowError[];
  reportCsv?: string;
}

import { Injectable } from '@nestjs/common';
import { ClubStatus, EventStatus, MeetingStatus, ReportStatus, Role } from '@prisma/client';
import { PrismaService } from '../prisma/prisma.service';
import type {
  AlertItem,
  AlertsData,
  DashboardWidget,
  IndicatorsData,
  ShortcutsData,
  UpcomingEventsData,
  UpcomingMeetingsData,
} from './dto/dashboard-response.dto';

const LIMIT_MEETINGS = 5;
const LIMIT_EVENTS = 5;
const LIMIT_ALERTS = 10;

@Injectable()
export class DashboardService {
  constructor(private readonly prisma: PrismaService) {}

  async getDashboard(userId: string, role: Role) {
    const widgets: DashboardWidget[] = [];

    if (role === Role.SECRETARY) {
      return this.getSecretaryDashboard(userId, widgets);
    }
    if (role === Role.PRESIDENT) {
      return this.getPresidentDashboard(userId, widgets);
    }
    return this.getParticipantDashboard(userId, widgets);
  }

  private async getSecretaryDashboard(
    userId: string,
    widgets: DashboardWidget[],
  ) {
    const [alerts, meetings, events, shortcuts] = await Promise.all([
      this.getAlertsSecretary(),
      this.getUpcomingMeetingsForSecretary(userId),
      this.getUpcomingEvents(),
      Promise.resolve(this.getShortcutsSecretary()),
    ]);

    if (alerts.items.length > 0) {
      widgets.push({
        id: 'alerts',
        type: 'alerts',
        title: 'Alertas',
        data: alerts,
        emptyMessage: 'Sin alertas pendientes',
      });
    }
    widgets.push({
      id: 'upcoming-meetings',
      type: 'list',
      title: 'Próximas reuniones',
      data: meetings,
      emptyMessage: 'No hay reuniones próximas',
    });
    widgets.push({
      id: 'upcoming-events',
      type: 'list',
      title: 'Próximos eventos',
      data: events,
      emptyMessage: 'No hay eventos próximos',
    });
    widgets.push({
      id: 'shortcuts',
      type: 'shortcuts',
      title: 'Accesos rápidos',
      data: shortcuts,
    });

    return { role: Role.SECRETARY, widgets };
  }

  private async getPresidentDashboard(userId: string, widgets: DashboardWidget[]) {
    const clubIds = await this.getUserClubIds(userId);
    const [alerts, meetings, events, shortcuts, indicators] = await Promise.all([
      this.getAlertsPresident(clubIds),
      this.getUpcomingMeetingsForParticipant(userId),
      this.getUpcomingEvents(),
      Promise.resolve(this.getShortcutsPresident()),
      clubIds.length > 0 ? this.getIndicators(clubIds[0]) : Promise.resolve({ items: [] }),
    ]);

    if (alerts.items.length > 0) {
      widgets.push({
        id: 'alerts',
        type: 'alerts',
        title: 'Alertas',
        data: alerts,
        emptyMessage: 'Sin alertas pendientes',
      });
    }
    widgets.push({
      id: 'upcoming-meetings',
      type: 'list',
      title: 'Próximas reuniones',
      data: meetings,
      emptyMessage: 'No tienes reuniones próximas',
    });
    widgets.push({
      id: 'upcoming-events',
      type: 'list',
      title: 'Próximos eventos',
      data: events,
      emptyMessage: 'No hay eventos próximos',
    });
    widgets.push({
      id: 'shortcuts',
      type: 'shortcuts',
      title: 'Accesos rápidos',
      data: shortcuts,
    });
    if (indicators.items.length > 0) {
      widgets.push({
        id: 'indicators',
        type: 'indicators',
        title: 'Indicadores del club',
        data: indicators,
        emptyMessage: 'No hay indicadores',
      });
    }

    return { role: Role.PRESIDENT, widgets };
  }

  private async getParticipantDashboard(userId: string, widgets: DashboardWidget[]) {
    const [meetings, events, shortcuts] = await Promise.all([
      this.getUpcomingMeetingsForParticipant(userId),
      this.getUpcomingEvents(),
      Promise.resolve(this.getShortcutsParticipant()),
    ]);

    widgets.push({
      id: 'upcoming-meetings',
      type: 'list',
      title: 'Próximas reuniones',
      data: meetings,
      emptyMessage: 'No tienes reuniones próximas',
    });
    widgets.push({
      id: 'upcoming-events',
      type: 'list',
      title: 'Próximos eventos',
      data: events,
      emptyMessage: 'No hay eventos próximos',
    });
    widgets.push({
      id: 'shortcuts',
      type: 'shortcuts',
      title: 'Accesos rápidos',
      data: shortcuts,
    });

    return { role: Role.PARTICIPANT, widgets };
  }

  private async getUserClubIds(userId: string): Promise<string[]> {
    const memberships = await this.prisma.membership.findMany({
      where: { userId },
      select: { clubId: true },
    });
    return memberships.map((m) => m.clubId);
  }

  private async getUpcomingMeetingsForParticipant(
    userId: string,
  ): Promise<UpcomingMeetingsData> {
    const now = new Date();
    const meetings = await this.prisma.meeting.findMany({
      where: {
        participants: { some: { userId } },
        status: { in: [MeetingStatus.SCHEDULED, MeetingStatus.LIVE] },
        OR: [
          { scheduledAt: { gte: now } },
          { scheduledAt: null },
          { status: MeetingStatus.LIVE },
        ],
      },
      orderBy: [{ scheduledAt: 'asc' }, { createdAt: 'desc' }],
      take: LIMIT_MEETINGS,
      include: { club: { select: { id: true, name: true } } },
    });

    return {
      items: meetings.map((m) => ({
        id: m.id,
        title: m.title,
        scheduledAt: m.scheduledAt?.toISOString() ?? '',
        status: m.status,
        href: `/meetings/${m.id}`,
      })),
      emptyActionHref: '/meetings',
    };
  }

  private async getUpcomingMeetingsForSecretary(
    _userId: string,
  ): Promise<UpcomingMeetingsData> {
    const now = new Date();
    const meetings = await this.prisma.meeting.findMany({
      where: {
        status: { in: [MeetingStatus.SCHEDULED, MeetingStatus.LIVE] },
        OR: [
          { scheduledAt: { gte: now } },
          { scheduledAt: null },
          { status: MeetingStatus.LIVE },
        ],
      },
      orderBy: [{ scheduledAt: 'asc' }, { createdAt: 'desc' }],
      take: LIMIT_MEETINGS,
      include: { club: { select: { id: true, name: true } } },
    });

    return {
      items: meetings.map((m) => ({
        id: m.id,
        title: m.title,
        scheduledAt: m.scheduledAt?.toISOString() ?? '',
        status: m.status,
        href: `/admin/meetings/${m.id}`,
      })),
      emptyActionHref: '/admin/meetings',
    };
  }

  private async getUpcomingEvents(): Promise<UpcomingEventsData> {
    const now = new Date();
    const events = await this.prisma.event.findMany({
      where: {
        status: EventStatus.PUBLISHED,
        startsAt: { gte: now },
      },
      orderBy: { startsAt: 'asc' },
      take: LIMIT_EVENTS,
    });

    return {
      items: events.map((e) => ({
        id: e.id,
        title: e.title,
        startsAt: e.startsAt.toISOString(),
        type: e.type,
        href: `/eventos/${e.id}`,
      })),
    };
  }

  private getShortcutsParticipant(): ShortcutsData {
    return {
      items: [
        { id: 'club', label: 'Mi Club', href: '/club' },
        { id: 'meetings', label: 'Reuniones', href: '/meetings' },
        { id: 'events', label: 'Eventos', href: '/eventos' },
      ],
    };
  }

  private getShortcutsPresident(): ShortcutsData {
    return {
      items: [
        { id: 'club', label: 'Mi Club', href: '/club' },
        { id: 'informe', label: 'Crear informe', href: '/club/informes/nuevo' },
        { id: 'meetings', label: 'Reuniones', href: '/meetings' },
        { id: 'events', label: 'Eventos', href: '/eventos' },
      ],
    };
  }

  private getShortcutsSecretary(): ShortcutsData {
    return {
      items: [
        { id: 'informes', label: 'Informes distrito', href: '/admin/district/informes' },
        { id: 'clubes', label: 'Clubes', href: '/admin/district/clubes' },
        { id: 'meetings', label: 'Reuniones', href: '/admin/meetings' },
        { id: 'comites', label: 'Comités', href: '/admin/district/comites' },
        { id: 'events', label: 'Eventos', href: '/admin/eventos' },
      ],
    };
  }

  private async getAlertsPresident(clubIds: string[]): Promise<AlertsData> {
    if (clubIds.length === 0) return { items: [] };

    const now = new Date();
    const period = await this.prisma.districtPeriod.findFirst({
      where: { isCurrent: true },
    });
    if (!period) return { items: [] };

    const reports = await this.prisma.report.findMany({
      where: {
        clubId: { in: clubIds },
        districtPeriodId: period.id,
        OR: [
          { status: ReportStatus.DRAFT },
          { status: ReportStatus.OBSERVED },
          { status: ReportStatus.REJECTED },
        ],
      },
      include: {
        club: { select: { id: true, name: true } },
        districtPeriod: { select: { name: true, endDate: true } },
      },
      take: LIMIT_ALERTS,
    });

    const items: AlertItem[] = reports.map((r) => {
      const isOverdue = period.endDate < now;
      const alertType: AlertItem['type'] =
        r.status === ReportStatus.OBSERVED || r.status === ReportStatus.REJECTED
          ? (r.status === ReportStatus.REJECTED ? 'report_rejected' : 'report_observed')
          : isOverdue
            ? 'report_overdue'
            : 'report_due';
      const message =
        r.status === ReportStatus.OBSERVED
          ? `Informe ${r.type} observado: ${r.club.name}`
          : r.status === ReportStatus.REJECTED
            ? `Informe ${r.type} rechazado: ${r.club.name}`
            : isOverdue
              ? `Informe ${r.type} vencido: ${r.club.name}`
              : `Informe ${r.type} próximo a vencer: ${r.club.name}`;
      return {
        id: r.id,
        type: alertType,
        message,
        href: `/club/informes/${r.id}`,
      };
    });

    return { items };
  }

  private async getAlertsSecretary(): Promise<{ items: AlertItem[] }> {
    const now = new Date();
    const period = await this.prisma.districtPeriod.findFirst({
      where: { isCurrent: true },
    });
    if (!period) return { items: [] };

    const [submittedReports, clubsWithOverdue] = await Promise.all([
      this.prisma.report.findMany({
        where: {
          districtPeriodId: period.id,
          status: ReportStatus.SUBMITTED,
        },
        include: { club: { select: { id: true, name: true } } },
        take: LIMIT_ALERTS,
      }),
      this.prisma.club.findMany({
        where: {
          status: ClubStatus.ACTIVE,
          reports: {
            none: {
              districtPeriodId: period.id,
            },
          },
        },
        select: { id: true, name: true },
      }),
    ]);

    const items: AlertItem[] = [];
    for (const r of submittedReports) {
      items.push({
        id: `submitted-${r.id}`,
        type: 'club_report_pending' as const,
        message: `Informe ${r.type} pendiente de revisión: ${r.club.name}`,
        href: `/admin/district/informes/${r.id}`,
      });
    }
    const periodEnded = period.endDate < now;
    if (periodEnded) {
      for (const c of clubsWithOverdue) {
        items.push({
          id: `overdue-club-${c.id}`,
          type: 'report_overdue' as const,
          message: `Club sin informe: ${c.name}`,
          href: `/admin/district/clubes/${c.id}`,
        });
      }
    }

    return { items: items.slice(0, LIMIT_ALERTS) };
  }

  private async getIndicators(clubId: string): Promise<IndicatorsData> {
    const club = await this.prisma.club.findUnique({
      where: { id: clubId },
      select: { informeAlDia: true, cuotaAldia: true, name: true },
    });
    if (!club) return { items: [] };

    return {
      items: [
        {
          id: 'informe',
          label: 'Informe al día',
          value: club.informeAlDia ? 'Sí' : 'No',
          href: '/club/informes',
        },
        {
          id: 'cuota',
          label: 'Cuota al día',
          value: club.cuotaAldia ? 'Sí' : 'No',
        },
      ],
    };
  }
}

import { Injectable, NotFoundException } from '@nestjs/common';
import { PrismaService } from '../../prisma/prisma.service';
import { ClubsService } from '../../clubs/clubs.service';

export interface DistrictClubsQuery {
  status?: 'ACTIVE' | 'INACTIVE';
  search?: string;
  informeAlDia?: boolean;
  enabledForDistrictMeetings?: boolean;
}

@Injectable()
export class DistrictClubsService {
  constructor(
    private readonly prisma: PrismaService,
    private readonly clubsService: ClubsService,
  ) {}

  async findAll(query: DistrictClubsQuery) {
    const where: Record<string, unknown> = {};
    if (query.status) where.status = query.status;
    if (query.informeAlDia !== undefined) where.informeAlDia = query.informeAlDia;
    if (query.enabledForDistrictMeetings !== undefined) {
      where.enabledForDistrictMeetings = query.enabledForDistrictMeetings;
    }
    if (query.search?.trim()) {
      const term = `%${query.search.trim().toLowerCase()}%`;
      where.OR = [
        { name: { contains: term, mode: 'insensitive' } },
        { code: { contains: term, mode: 'insensitive' } },
      ];
    }

    return this.prisma.club.findMany({
      where,
      orderBy: { name: 'asc' },
    });
  }

  async findOne(id: string) {
    const club = await this.clubsService.findOne(id);
    const [memberships, recentReports] = await Promise.all([
      this.prisma.membership.findMany({
        where: {
          clubId: id,
          OR: [{ activeUntil: null }, { activeUntil: { gte: new Date() } }],
        },
        orderBy: [{ isPresident: 'desc' }, { activeFrom: 'desc' }],
        include: {
          user: { select: { id: true, fullName: true, email: true } },
        },
      }),
      this.prisma.report.findMany({
        where: { clubId: id },
        take: 5,
        orderBy: { submittedAt: 'desc' },
        include: {
          districtPeriod: { select: { id: true, name: true } },
        },
      }),
    ]);

    return {
      ...club,
      authorities: memberships.map((m) => ({
        userId: m.userId,
        fullName: m.user.fullName,
        email: m.user.email,
        title: m.title,
        isPresident: m.isPresident,
        activeFrom: m.activeFrom,
        activeUntil: m.activeUntil,
      })),
      recentReports,
    };
  }

  async findClubReports(clubId: string, periodId?: string) {
    await this.clubsService.findOne(clubId);
    const where: Record<string, unknown> = { clubId };
    if (periodId) where.districtPeriodId = periodId;
    const items = await this.prisma.report.findMany({
      where,
      orderBy: [{ submittedAt: 'desc' }, { createdAt: 'desc' }],
      include: {
        districtPeriod: { select: { id: true, name: true, startDate: true, endDate: true } },
      },
    });
    return { items };
  }
}

