import { Injectable, NotFoundException, ForbiddenException } from '@nestjs/common';
import { PrismaService } from '../../prisma/prisma.service';
import { ReportStatus, ReportType } from '@prisma/client';
import { QueryReportsDto } from './dto/query-reports.dto';
import { UpdateReportDto } from './dto/update-report.dto';

@Injectable()
export class ReportsService {
  constructor(private readonly prisma: PrismaService) {}

  async findAll(query: QueryReportsDto) {
    const { periodId, clubId, status, type, page = '1', limit = '20' } = query;
    const skip = (Math.max(1, parseInt(page, 10)) - 1) * Math.min(100, Math.max(1, parseInt(limit, 10)));
    const take = Math.min(100, Math.max(1, parseInt(limit, 10)));

    const where: Record<string, unknown> = {};
    if (periodId) where.districtPeriodId = periodId;
    if (clubId) where.clubId = clubId;
    if (status) where.status = status;
    if (type) where.type = type;

    const [items, total] = await Promise.all([
      this.prisma.report.findMany({
        where,
        skip,
        take,
        orderBy: [{ submittedAt: 'desc' }, { createdAt: 'desc' }],
        include: {
          club: { select: { id: true, name: true, code: true } },
          districtPeriod: { select: { id: true, name: true, startDate: true, endDate: true } },
          reviewer: { select: { id: true, fullName: true, email: true } },
        },
      }),
      this.prisma.report.count({ where }),
    ]);

    return { items, total, page: parseInt(page, 10), limit: take };
  }

  async findMissing(periodId: string, type?: ReportType) {
    const period = await this.prisma.districtPeriod.findUnique({
      where: { id: periodId },
    });
    if (!period) throw new NotFoundException('Período no encontrado');

    const activeClubs = await this.prisma.club.findMany({
      where: { status: 'ACTIVE' },
      select: { id: true, name: true, code: true },
    });

    const types = type ? [type] : (Object.keys(ReportType) as ReportType[]);
    const reported = await this.prisma.report.findMany({
      where: {
        districtPeriodId: periodId,
        status: { not: 'DRAFT' },
        type: type ? type : { in: types },
      },
      select: { clubId: true, type: true },
    });
    const reportedSet = new Set(reported.map((r) => `${r.clubId}:${r.type}`));

    const missing: { clubId: string; clubName: string; clubCode: string; type: ReportType }[] = [];
    for (const club of activeClubs) {
      for (const t of types) {
        if (!reportedSet.has(`${club.id}:${t}`)) {
          missing.push({
            clubId: club.id,
            clubName: club.name,
            clubCode: club.code,
            type: t,
          });
        }
      }
    }
    return { periodId, periodName: period.name, missing };
  }

  async getSummary(periodId: string, type?: ReportType) {
    const period = await this.prisma.districtPeriod.findUnique({
      where: { id: periodId },
    });
    if (!period) throw new NotFoundException('Período no encontrado');

    const activeClubsCount = await this.prisma.club.count({
      where: { status: 'ACTIVE' },
    });

    const types = type ? [type] : (Object.keys(ReportType) as ReportType[]);
    const reports = await this.prisma.report.findMany({
      where: {
        districtPeriodId: periodId,
        status: { in: ['SUBMITTED', 'OBSERVED', 'APPROVED'] },
        type: type ? type : { in: types },
      },
      select: { clubId: true, status: true, type: true },
    });

    const byStatus = reports.reduce(
      (acc, r) => {
        acc[r.status] = (acc[r.status] || 0) + 1;
        return acc;
      },
      {} as Record<string, number>,
    );
    const submittedCount = reports.length;
    const approvedCount = byStatus['APPROVED'] || 0;
    const pctAlDia = activeClubsCount > 0 ? Math.round((submittedCount / (activeClubsCount * types.length)) * 100) : 0;

    return {
      periodId,
      periodName: period.name,
      activeClubsCount,
      reportsSubmitted: submittedCount,
      reportsApproved: approvedCount,
      reportsObserved: byStatus['OBSERVED'] || 0,
      pctClubesAlDia: pctAlDia,
      byStatus,
    };
  }

  async findOne(id: string) {
    const report = await this.prisma.report.findUnique({
      where: { id },
      include: {
        club: { select: { id: true, name: true, code: true } },
        districtPeriod: { select: { id: true, name: true, startDate: true, endDate: true } },
        reviewer: { select: { id: true, fullName: true, email: true } },
      },
    });
    if (!report) throw new NotFoundException('Informe no encontrado');
    return report;
  }

  async update(id: string, dto: UpdateReportDto, userId: string) {
    const report = await this.prisma.report.findUnique({ where: { id } });
    if (!report) throw new NotFoundException('Informe no encontrado');
    if (
      dto.status &&
      !['OBSERVED', 'APPROVED', 'REJECTED'].includes(dto.status)
    ) {
      throw new ForbiddenException(
        'Solo se puede marcar OBSERVED, APPROVED o REJECTED',
      );
    }

    const data: Record<string, unknown> = {
      ...(dto.observations !== undefined && { observations: dto.observations ?? null }),
      ...(dto.status && {
        status: dto.status,
        reviewedAt: new Date(),
        reviewedById: userId,
      }),
    };
    return this.prisma.report.update({
      where: { id },
      data,
      include: {
        club: { select: { id: true, name: true, code: true } },
        districtPeriod: { select: { id: true, name: true } },
        reviewer: { select: { id: true, fullName: true } },
      },
    });
  }
}

import {
  BadRequestException,
  ForbiddenException,
  Injectable,
  NotFoundException,
} from '@nestjs/common';
import { plainToInstance } from 'class-transformer';
import { validate } from 'class-validator';
import { EventStatus, EventType, Role } from '@prisma/client';
import { PrismaService } from '../prisma/prisma.service';
import { CsvParserService } from '../common/bulk/csv-parser.service';
import { BulkImportResult } from '../common/bulk/bulk-result.types';
import { CreateEventDto } from './dto/create-event.dto';
import { QueryEventsDto } from './dto/query-events.dto';
import { UpdateEventDto } from './dto/update-event.dto';

const eventInclude = {
  club: { select: { id: true, name: true, code: true } },
  organizer: { select: { id: true, fullName: true, email: true } },
};

@Injectable()
export class EventsService {
  constructor(
    private readonly prisma: PrismaService,
    private readonly csvParser: CsvParserService,
  ) {}

  private async getPresidentClubIds(userId: string): Promise<string[]> {
    const memberships = await this.prisma.membership.findMany({
      where: { userId, isPresident: true },
      select: { clubId: true },
    });
    return memberships.map((m) => m.clubId);
  }

  private async canAccessEvent(
    event: { clubId: string | null },
    userId: string,
    role: Role,
  ): Promise<boolean> {
    if (role === Role.SECRETARY) return true;
    if (role === Role.PARTICIPANT) return false; // DRAFT only - PARTICIPANT never sees DRAFT
    if (role === Role.PRESIDENT) {
      if (!event.clubId) return false; // PRESIDENT cannot access draft distrital events
      const clubIds = await this.getPresidentClubIds(userId);
      return clubIds.includes(event.clubId);
    }
    return false;
  }

  private async buildWhereForList(
    dto: QueryEventsDto,
    userId: string,
    role: Role,
  ): Promise<Record<string, unknown>> {
    const now = new Date();
    const where: Record<string, unknown> = {};

    // PARTICIPANT: only PUBLISHED, CANCELLED, FINISHED
    if (role === Role.PARTICIPANT) {
      where.status = { in: [EventStatus.PUBLISHED, EventStatus.CANCELLED, EventStatus.FINISHED] };
    }

    if (dto.status) where.status = dto.status;
    if (dto.type) where.type = dto.type;
    if (dto.modality) where.modality = dto.modality;
    if (dto.clubId) where.clubId = dto.clubId;
    if (dto.organizerId) where.organizerId = dto.organizerId;
    if (dto.featured === true) where.featured = true;

    if (dto.upcoming) {
      where.startsAt = { gte: now };
    } else if (dto.past) {
      where.startsAt = { lt: now };
    }

    if (dto.from || dto.to) {
      where.startsAt = where.startsAt || {};
      if (dto.from) {
        (where.startsAt as Record<string, Date>).gte = new Date(dto.from);
      }
      if (dto.to) {
        (where.startsAt as Record<string, Date>).lte = new Date(dto.to);
      }
    }

    // PRESIDENT: always restrict to their clubs (admin sees only events they can manage)
    if (role === Role.PRESIDENT) {
      const clubIds = await this.getPresidentClubIds(userId);
      if (clubIds.length === 0) {
        where.clubId = '__no_club__'; // impossible - returns empty
      } else {
        const filterClubId = dto.clubId && clubIds.includes(dto.clubId) ? dto.clubId : undefined;
        where.clubId = filterClubId ?? { in: clubIds };
      }
    }

    return where;
  }

  async findAll(dto: QueryEventsDto, userId: string, role: Role) {
    const where = await this.buildWhereForList(dto, userId, role);

    const page = dto.page ?? 1;
    const limit = dto.limit ?? 20;
    const skip = (page - 1) * limit;

    const [data, total] = await Promise.all([
      this.prisma.event.findMany({
        where,
        orderBy: [{ featured: 'desc' }, { startsAt: 'asc' }, { createdAt: 'desc' }],
        skip,
        take: limit,
        include: eventInclude,
      }),
      this.prisma.event.count({ where }),
    ]);

    return { data, total, page, limit };
  }

  async findUpcoming(limit = 5) {
    const now = new Date();
    return this.prisma.event.findMany({
      where: {
        status: EventStatus.PUBLISHED,
        startsAt: { gte: now },
      },
      orderBy: [{ featured: 'desc' }, { startsAt: 'asc' }],
      take: limit,
      include: eventInclude,
    });
  }

  async findPast(page = 1, limit = 20) {
    const now = new Date();
    const skip = (page - 1) * limit;

    const [data, total] = await Promise.all([
      this.prisma.event.findMany({
        where: {
          status: { in: [EventStatus.PUBLISHED, EventStatus.CANCELLED, EventStatus.FINISHED] },
          startsAt: { lt: now },
        },
        orderBy: { startsAt: 'desc' },
        skip,
        take: limit,
        include: eventInclude,
      }),
      this.prisma.event.count({
        where: {
          status: { in: [EventStatus.PUBLISHED, EventStatus.CANCELLED, EventStatus.FINISHED] },
          startsAt: { lt: now },
        },
      }),
    ]);

    return { data, total, page, limit };
  }

  async findOne(id: string, userId: string, role: Role) {
    const event = await this.prisma.event.findUnique({
      where: { id },
      include: eventInclude,
    });
    if (!event) throw new NotFoundException('Evento no encontrado');

    if (event.status === EventStatus.DRAFT) {
      const canAccess = await this.canAccessEvent(event, userId, role);
      if (!canAccess) {
        throw new NotFoundException('Evento no encontrado');
      }
    }

    return event;
  }

  private async assertCanManageEvent(
    eventId: string,
    userId: string,
    role: Role,
  ): Promise<{ event: Awaited<ReturnType<typeof this.prisma.event.findUnique>> }> {
    const event = await this.prisma.event.findUnique({
      where: { id: eventId },
      include: eventInclude,
    });
    if (!event) throw new NotFoundException('Evento no encontrado');

    if (role === Role.SECRETARY) return { event };
    if (role === Role.PRESIDENT) {
      if (!event.clubId) {
        throw new ForbiddenException('Solo el equipo distrital puede gestionar eventos distritales');
      }
      const clubIds = await this.getPresidentClubIds(userId);
      if (!clubIds.includes(event.clubId)) {
        throw new ForbiddenException('No podés gestionar eventos de otros clubes');
      }
      return { event };
    }
    throw new ForbiddenException('No tenés permiso para gestionar este evento');
  }

  getBulkTemplate(): { buffer: Buffer; filename: string } {
    const header = [
      'title',
      'description',
      'type',
      'modality',
      'startsAt',
      'endsAt',
      'location',
      'meetingUrl',
      'maxCapacity',
      'featured',
      'clubId',
    ];
    const example = [
      'Encuentro distrital',
      'Reunión trimestral',
      'DISTRITAL',
      'PRESENCIAL',
      '2025-04-15 09:00',
      '',
      'Hotel XYZ',
      '',
      '200',
      'true',
      '',
    ];
    const buffer = this.csvParser.generateTemplateCsv(header, example);
    return { buffer, filename: 'plantilla-eventos.csv' };
  }

  private parseBool(val: string | undefined, defaultVal: boolean): boolean {
    if (!val || val.trim() === '') return defaultVal;
    const v = val.trim().toLowerCase();
    return v === 'true' || v === '1' || v === 'sí' || v === 'si' || v === 'yes';
  }

  async bulkImport(
    file: Express.Multer.File | undefined,
    userId: string,
    role: Role,
    mode: 'partial' | 'strict' = 'partial',
  ): Promise<BulkImportResult> {
    if (!file?.buffer) {
      throw new BadRequestException('Archivo CSV requerido');
    }

    const rows = this.csvParser.parse(file.buffer);
    const result: BulkImportResult = {
      total: rows.length,
      created: 0,
      failed: 0,
      mode,
      createdIds: [],
      errors: [],
    };

    for (let i = 0; i < rows.length; i++) {
      const row = rows[i];
      const rowNum = i + 2;

      let clubId: string | null = row.clubId?.trim() || null;

      if (role === Role.PRESIDENT && !clubId) {
        result.errors.push({
          row: rowNum,
          data: row as Record<string, unknown>,
          message: 'Los presidentes deben asociar un club al evento',
        });
        result.failed++;
        if (mode === 'strict') {
          for (let j = i + 1; j < rows.length; j++) {
            result.errors.push({
              row: j + 2,
              data: rows[j] as Record<string, unknown>,
              message: 'Importación abortada (modo estricto)',
            });
            result.failed++;
          }
          return result;
        }
        continue;
      }

      if (clubId && role === Role.PRESIDENT) {
        const clubIds = await this.getPresidentClubIds(userId);
        const club = await this.prisma.club.findFirst({
          where: {
            OR: [{ id: clubId }, { code: clubId.toUpperCase() }],
          },
        });
        if (club && !clubIds.includes(club.id)) {
          result.errors.push({
            row: rowNum,
            data: row as Record<string, unknown>,
            message: 'Solo podés asignar tu club al evento',
          });
          result.failed++;
          if (mode === 'strict') {
            for (let j = i + 1; j < rows.length; j++) {
              result.errors.push({
                row: j + 2,
                data: rows[j] as Record<string, unknown>,
                message: 'Importación abortada (modo estricto)',
              });
              result.failed++;
            }
            return result;
          }
          continue;
        }
      }

      const dto = plainToInstance(CreateEventDto, {
        title: row.title?.trim() || '',
        description: row.description?.trim() || undefined,
        type: row.type?.trim() || 'DISTRITAL',
        modality: row.modality?.trim() || 'PRESENCIAL',
        startsAt: row.startsAt?.trim() || new Date().toISOString(),
        endsAt: row.endsAt?.trim() || undefined,
        location: row.location?.trim() || undefined,
        meetingUrl: row.meetingUrl?.trim() || undefined,
        maxCapacity: row.maxCapacity ? parseInt(row.maxCapacity, 10) : undefined,
        featured: this.parseBool(row.featured, false),
        clubId: clubId || undefined,
      });

      const validationErrors = await validate(dto);
      if (validationErrors.length > 0) {
        const msg = validationErrors
          .map((e) => Object.values(e.constraints || {}).join(', '))
          .join('; ');
        result.errors.push({
          row: rowNum,
          data: row as Record<string, unknown>,
          message: msg,
        });
        result.failed++;
        if (mode === 'strict') {
          for (let j = i + 1; j < rows.length; j++) {
            result.errors.push({
              row: j + 2,
              data: rows[j] as Record<string, unknown>,
              message: 'Importación abortada (modo estricto)',
            });
            result.failed++;
          }
          return result;
        }
        continue;
      }

      try {
        if (clubId) {
          const club = await this.prisma.club.findFirst({
            where: {
              OR: [{ id: clubId }, { code: clubId.toUpperCase() }],
            },
          });
          if (club) clubId = club.id;
        }

        const event = await this.prisma.event.create({
          data: {
            title: (dto as CreateEventDto).title.trim(),
            description: (dto as CreateEventDto).description?.trim() || null,
            type: (dto as CreateEventDto).type,
            modality: (dto as CreateEventDto).modality,
            startsAt: new Date((dto as CreateEventDto).startsAt),
            endsAt: (dto as CreateEventDto).endsAt
              ? new Date((dto as CreateEventDto).endsAt!)
              : null,
            location: (dto as CreateEventDto).location?.trim() || null,
            meetingUrl: (dto as CreateEventDto).meetingUrl?.trim() || null,
            maxCapacity: (dto as CreateEventDto).maxCapacity ?? null,
            featured: (dto as CreateEventDto).featured ?? false,
            clubId,
            organizerId: userId,
            status: EventStatus.DRAFT,
          },
        });
        result.created++;
        result.createdIds!.push(event.id);
      } catch (err) {
        const msg = err instanceof Error ? err.message : 'Error desconocido';
        result.errors.push({
          row: rowNum,
          data: row as Record<string, unknown>,
          message: msg,
        });
        result.failed++;
        if (mode === 'strict') {
          for (let j = i + 1; j < rows.length; j++) {
            result.errors.push({
              row: j + 2,
              data: rows[j] as Record<string, unknown>,
              message: `Importación abortada: ${msg}`,
            });
            result.failed++;
          }
          return result;
        }
      }
    }

    if (result.errors.length > 0) {
      result.reportCsv = this.csvParser.generateReportCsv(
        [
          'title',
          'description',
          'type',
          'modality',
          'startsAt',
          'endsAt',
          'location',
          'meetingUrl',
          'maxCapacity',
          'featured',
          'clubId',
        ],
        result.errors,
      );
    }

    return result;
  }

  async create(dto: CreateEventDto, userId: string, role: Role) {
    if (role === Role.PARTICIPANT) {
      throw new ForbiddenException('No tenés permiso para crear eventos');
    }

    if (role === Role.PRESIDENT && dto.clubId) {
      const clubIds = await this.getPresidentClubIds(userId);
      if (!clubIds.includes(dto.clubId)) {
        throw new ForbiddenException('Solo podés crear eventos para tu club');
      }
    }

    if (role === Role.PRESIDENT && !dto.clubId) {
      throw new ForbiddenException('Los presidentes deben asociar un club al evento');
    }

    const data: Parameters<typeof this.prisma.event.create>[0]['data'] = {
      title: dto.title.trim(),
      description: dto.description?.trim() || null,
      type: dto.type,
      modality: dto.modality,
      startsAt: new Date(dto.startsAt),
      endsAt: dto.endsAt ? new Date(dto.endsAt) : null,
      location: dto.location?.trim() || null,
      meetingUrl: dto.meetingUrl?.trim() || null,
      maxCapacity: dto.maxCapacity ?? null,
      featured: dto.featured ?? false,
      imageUrl: dto.imageUrl?.trim() || null,
      clubId: dto.clubId || null,
      organizerId: userId,
      status: EventStatus.DRAFT,
    };

    return this.prisma.event.create({
      data,
      include: eventInclude,
    });
  }

  async update(id: string, dto: UpdateEventDto, userId: string, role: Role) {
    await this.assertCanManageEvent(id, userId, role);

    if (dto.clubId !== undefined && role === Role.PRESIDENT) {
      const clubIds = await this.getPresidentClubIds(userId);
      if (!clubIds.includes(dto.clubId)) {
        throw new ForbiddenException('Solo podés asignar tu club al evento');
      }
    }

    const data: Parameters<typeof this.prisma.event.update>[0]['data'] = {};
    if (dto.title != null) data.title = dto.title.trim();
    if (dto.description !== undefined) data.description = dto.description?.trim() || null;
    if (dto.type != null) data.type = dto.type;
    if (dto.modality != null) data.modality = dto.modality;
    if (dto.startsAt != null) data.startsAt = new Date(dto.startsAt);
    if (dto.endsAt !== undefined) data.endsAt = dto.endsAt ? new Date(dto.endsAt) : null;
    if (dto.location !== undefined) data.location = dto.location?.trim() || null;
    if (dto.meetingUrl !== undefined) data.meetingUrl = dto.meetingUrl?.trim() || null;
    if (dto.maxCapacity !== undefined) data.maxCapacity = dto.maxCapacity ?? null;
    if (dto.featured !== undefined) data.featured = dto.featured;
    if (dto.imageUrl !== undefined) data.imageUrl = dto.imageUrl?.trim() || null;
    if (dto.clubId !== undefined) data.clubId = dto.clubId || null;
    if (dto.status != null) data.status = dto.status;

    return this.prisma.event.update({
      where: { id },
      data,
      include: eventInclude,
    });
  }

  async remove(id: string, userId: string, role: Role) {
    await this.assertCanManageEvent(id, userId, role);
    return this.prisma.event.delete({
      where: { id },
      include: eventInclude,
    });
  }

  async publish(id: string, userId: string, role: Role) {
    const { event } = await this.assertCanManageEvent(id, userId, role);
    if (event.status !== EventStatus.DRAFT) {
      throw new BadRequestException('Solo se puede publicar un evento en borrador');
    }
    return this.prisma.event.update({
      where: { id },
      data: { status: EventStatus.PUBLISHED },
      include: eventInclude,
    });
  }

  async cancel(id: string, userId: string, role: Role) {
    const { event } = await this.assertCanManageEvent(id, userId, role);
    if (event.status !== EventStatus.PUBLISHED) {
      throw new BadRequestException('Solo se puede cancelar un evento publicado');
    }
    return this.prisma.event.update({
      where: { id },
      data: { status: EventStatus.CANCELLED },
      include: eventInclude,
    });
  }

  async markFinished(id: string, userId: string, role: Role) {
    const { event } = await this.assertCanManageEvent(id, userId, role);
    if (event.status !== EventStatus.PUBLISHED) {
      throw new BadRequestException('Solo se puede marcar como finalizado un evento publicado');
    }
    return this.prisma.event.update({
      where: { id },
      data: { status: EventStatus.FINISHED },
      include: eventInclude,
    });
  }
}

import { IsOptional, IsString, IsUUID, MinLength } from 'class-validator';

export class CreateMeetingDto {
  @IsString()
  @MinLength(1)
  title: string;

  @IsOptional()
  @IsString()
  description?: string;

  @IsOptional()
  scheduledAt?: string; // ISO date

  @IsString()
  clubId: string;
}

import {
  WebSocketGateway,
  WebSocketServer,
  SubscribeMessage,
  OnGatewayConnection,
  OnGatewayDisconnect,
} from '@nestjs/websockets';
import { forwardRef, Inject } from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { Server } from 'socket.io';
import { VoteChoice } from '@prisma/client';
import { AuditService } from '../audit/audit.service';
import { PrismaService } from '../prisma/prisma.service';
import { VotingService } from '../voting/voting.service';

const MEETING_ROOM_PREFIX = 'meeting:';

interface SocketWithData {
  id: string;
  join: (r: string) => void;
  leave: (r: string) => void;
  handshake?: { auth?: { token?: string }; query?: { token?: string } };
  data?: { userId?: string; meetingIds?: string[] };
  rooms?: Set<string> | string[];
}

@WebSocketGateway({ cors: { origin: process.env.CORS_ORIGIN ?? 'http://localhost:3000' } })
export class RealtimeGateway implements OnGatewayConnection, OnGatewayDisconnect {
  @WebSocketServer()
  server!: Server;

  constructor(
    private readonly prisma: PrismaService,
    private readonly jwtService: JwtService,
    private readonly audit: AuditService,
    @Inject(forwardRef(() => VotingService))
    private readonly votingService: VotingService,
  ) {}

  handleConnection() {}

  async handleDisconnect(client: SocketWithData) {
    const meetingIds = client.data?.meetingIds ?? [];
    const userId = client.data?.userId;
    for (const meetingId of meetingIds) {
      if (userId) {
        await this.markParticipantLeft(meetingId, userId);
      }
    }
    client.data = {};
  }

  private getUserIdFromClient(client: SocketWithData): string | null {
    const token =
      client.handshake?.auth?.token ||
      (typeof client.handshake?.query?.token === 'string' ? client.handshake.query.token : null);
    if (!token) return null;
    try {
      const payload = this.jwtService.verify<{ sub: string }>(token);
      return payload.sub ?? null;
    } catch {
      return null;
    }
  }

  @SubscribeMessage('join_meeting')
  async handleJoinMeeting(client: SocketWithData, payload: { meetingId: string; userId?: string }) {
    return this.doJoinMeeting(client, payload);
  }

  @SubscribeMessage('meeting.join')
  async handleMeetingJoin(client: SocketWithData, payload: { meetingId: string; userId?: string }) {
    return this.doJoinMeeting(client, payload);
  }

  private async doJoinMeeting(
    client: SocketWithData,
    payload: { meetingId: string; userId?: string },
  ) {
    const { meetingId } = payload;
    if (!meetingId) {
      return { event: 'error', data: { message: 'meetingId required' } };
    }
    const userId = this.getUserIdFromClient(client);
    if (!userId) {
      return { event: 'error', data: { message: 'Token requerido o inválido' } };
    }
    const meeting = await this.prisma.meeting.findUnique({
      where: { id: meetingId },
      select: { id: true },
    });
    if (!meeting) {
      return { event: 'error', data: { message: 'Reunión no encontrada' } };
    }
    const isParticipant = await this.prisma.meetingParticipant.findFirst({
      where: { meetingId, userId },
    });
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      select: { role: true },
    });
    const isModerator = user?.role === 'SECRETARY' || user?.role === 'PRESIDENT';
    if (!isParticipant && !isModerator) {
      return { event: 'error', data: { message: 'No tenés acceso a esta reunión' } };
    }
    client.data = client.data ?? {};
    client.data.userId = userId;
    if (!Array.isArray(client.data.meetingIds)) client.data.meetingIds = [];
    if (!client.data.meetingIds.includes(meetingId)) client.data.meetingIds.push(meetingId);
    client.join(MEETING_ROOM_PREFIX + meetingId);
    const participant = await this.prisma.meetingParticipant.findUnique({
      where: { meetingId_userId: { meetingId, userId } },
    });
    if (participant) {
      await this.prisma.meetingParticipant.update({
        where: { id: participant.id },
        data: {
          attendanceStatus: 'JOINED',
          ...(participant.joinedAt ? {} : { joinedAt: new Date() }),
        },
      });
      await this.audit.log({
        meetingId,
        actorUserId: userId,
        action: 'participant.joined',
        entityType: 'MeetingParticipant',
        entityId: participant.id,
      });
      await this.broadcastSnapshot(meetingId);
    }
    const snapshot = await this.buildSnapshot(meetingId, userId);
    return { event: 'meeting.snapshot', data: snapshot };
  }

  private async markParticipantLeft(meetingId: string, userId: string) {
    const participant = await this.prisma.meetingParticipant.findUnique({
      where: { meetingId_userId: { meetingId, userId } },
    });
    if (participant) {
      await this.prisma.meetingParticipant.update({
        where: { id: participant.id },
        data: { attendanceStatus: 'LEFT' },
      });
      await this.audit.log({
        meetingId,
        actorUserId: userId,
        action: 'participant.left',
        entityType: 'MeetingParticipant',
        entityId: participant.id,
      });
      await this.broadcastSnapshot(meetingId);
    }
  }

  @SubscribeMessage('leave_meeting')
  async handleLeaveMeeting(client: SocketWithData, payload: { meetingId: string }) {
    const meetingId = payload.meetingId;
    if (meetingId) {
      const userId = client.data?.userId;
      if (userId) await this.markParticipantLeft(meetingId, userId);
      if (Array.isArray(client.data?.meetingIds)) {
        client.data.meetingIds = client.data.meetingIds.filter((id) => id !== meetingId);
      }
    }
    client.leave(MEETING_ROOM_PREFIX + meetingId);
  }

  @SubscribeMessage('vote.submit')
  async handleVoteSubmit(
    client: SocketWithData,
    payload: { meetingId: string; voteSessionId: string; choice: VoteChoice },
  ) {
    const userId = client.data?.userId;
    if (!userId) {
      return { event: 'error', data: { message: 'No autenticado' } };
    }
    const { meetingId, voteSessionId, choice } = payload;
    if (!meetingId || !voteSessionId || !choice) {
      return { event: 'error', data: { message: 'meetingId, voteSessionId y choice requeridos' } };
    }
    const room = MEETING_ROOM_PREFIX + meetingId;
    const inRoom = Array.isArray(client.rooms) ? client.rooms.includes(room) : client.rooms?.has?.(room);
    if (!inRoom) {
      return { event: 'error', data: { message: 'No estás en esta reunión' } };
    }
    try {
      const result = await this.votingService.submitVote(meetingId, voteSessionId, userId, choice);
      return { event: 'vote.confirmed', data: result };
    } catch (err: unknown) {
      const message = err && typeof err === 'object' && 'message' in err ? String((err as { message: unknown }).message) : 'Error al registrar el voto';
      return { event: 'error', data: { message } };
    }
  }

  async emitToMeeting(meetingId: string, event: string, data: unknown) {
    this.server.to(MEETING_ROOM_PREFIX + meetingId).emit(event, data);
  }

  async broadcastSnapshot(meetingId: string) {
    const snapshot = await this.buildSnapshot(meetingId);
    await this.emitToMeeting(meetingId, 'meeting.snapshot', snapshot);
  }

  private async buildSnapshot(meetingId: string, userId?: string) {
    const meeting = await this.prisma.meeting.findUnique({
      where: { id: meetingId },
      include: {
        topics: { orderBy: { order: 'asc' } },
        voteSessions: { where: { status: 'OPEN' }, include: { topic: true } },
        participants: { include: { user: { select: { id: true, fullName: true } } } },
        speakingRequests: {
          where: { status: { in: ['PENDING', 'ACCEPTED'] } },
          orderBy: { position: 'asc' },
          include: { user: { select: { id: true, fullName: true } } },
        },
      },
    });
    if (!meeting) return null;
    const currentTopic = meeting.currentTopicId
      ? meeting.topics.find((t) => t.id === meeting.currentTopicId)
      : null;
    const openVoteSession = meeting.voteSessions[0];
    let ownVote: { voteSessionId: string; choice: string } | null = null;
    if (userId && openVoteSession) {
      const vote = await this.prisma.vote.findUnique({
        where: { voteSessionId_userId: { voteSessionId: openVoteSession.id, userId } },
      });
      if (vote) ownVote = { voteSessionId: vote.voteSessionId, choice: vote.choice };
    }
    const lastClosedSession = await this.prisma.voteSession.findFirst({
      where: { meetingId, status: 'CLOSED' },
      orderBy: { closedAt: 'desc' },
    });
    let voteResult: {
      voteSessionId: string;
      topicId: string;
      counts: { yes: number; no: number; abstain: number };
      total: number;
    } | null = null;
    if (lastClosedSession) {
      const counts = await this.prisma.vote.groupBy({
        by: ['choice'],
        where: { voteSessionId: lastClosedSession.id },
        _count: true,
      });
      const map = Object.fromEntries(counts.map((c) => [c.choice, c._count]));
      const yes = map.YES ?? 0;
      const no = map.NO ?? 0;
      const abstain = map.ABSTAIN ?? 0;
      voteResult = {
        voteSessionId: lastClosedSession.id,
        topicId: lastClosedSession.topicId,
        counts: { yes, no, abstain },
        total: yes + no + abstain,
      };
    }
    const activeTimers = await this.prisma.timerSession.findMany({
      where: { meetingId, endedAt: null },
      orderBy: { startedAt: 'desc' },
    });
    const now = Date.now();
    const timers = activeTimers.map((t) => {
      const elapsed = Math.floor((now - t.startedAt.getTime()) / 1000);
      const overtime = Math.max(0, elapsed - t.plannedDurationSec);
      return {
        id: t.id,
        type: t.type,
        topicId: t.topicId ?? undefined,
        speakingRequestId: t.speakingRequestId ?? undefined,
        plannedDurationSec: t.plannedDurationSec,
        startedAt: t.startedAt.toISOString(),
        pausedAt: t.pausedAt?.toISOString(),
        overtimeSec: t.overtimeSec,
        elapsedSec: elapsed,
      };
    });
    const currentSpeaker = meeting.currentSpeakerId
      ? await this.prisma.user.findUnique({ where: { id: meeting.currentSpeakerId }, select: { id: true, fullName: true } })
      : null;
    const nextSpeaker = meeting.nextSpeakerId
      ? await this.prisma.user.findUnique({ where: { id: meeting.nextSpeakerId }, select: { id: true, fullName: true } })
      : null;
    return {
      meeting: {
        id: meeting.id,
        title: meeting.title,
        status: meeting.status,
        currentTopicId: meeting.currentTopicId,
        currentSpeakerId: meeting.currentSpeakerId,
        nextSpeakerId: meeting.nextSpeakerId,
        startedAt: meeting.startedAt?.toISOString() ?? null,
        scheduledAt: meeting.scheduledAt?.toISOString() ?? null,
        endedAt: meeting.endedAt?.toISOString() ?? null,
      },
      currentTopic: currentTopic
        ? {
            id: currentTopic.id,
            meetingId: currentTopic.meetingId,
            title: currentTopic.title,
            description: currentTopic.description,
            order: currentTopic.order,
            type: currentTopic.type,
            estimatedDurationSec: currentTopic.estimatedDurationSec,
            status: currentTopic.status,
          }
        : null,
      topics: meeting.topics.map((t) => ({
        id: t.id,
        title: t.title,
        description: t.description,
        order: t.order,
        type: t.type,
        estimatedDurationSec: t.estimatedDurationSec,
        status: t.status,
      })),
      activeVote: openVoteSession
        ? {
            voteSessionId: openVoteSession.id,
            topicId: openVoteSession.topicId,
            topicTitle: openVoteSession.topic.title,
            openedAt: openVoteSession.openedAt.toISOString(),
          }
        : null,
      ownVote,
      voteResult,
      timers,
      speakingQueue: meeting.speakingRequests.map((r) => ({
        id: r.id,
        meetingId: r.meetingId,
        userId: r.userId,
        status: r.status,
        position: r.position,
        requestedAt: r.requestedAt.toISOString(),
        acceptedAt: r.acceptedAt?.toISOString(),
        user: r.user,
      })),
      currentSpeaker: currentSpeaker ? { id: currentSpeaker.id, fullName: currentSpeaker.fullName } : null,
      nextSpeaker: nextSpeaker ? { id: nextSpeaker.id, fullName: nextSpeaker.fullName } : null,
      participants: meeting.participants.map((p) => ({
        userId: p.userId,
        fullName: p.user.fullName,
        attendanceStatus: p.attendanceStatus,
        canVote: p.canVote,
      })),
    };
  }
}

import { Body, Controller, Get, Param, Post, UseGuards } from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { Role } from '@prisma/client';
import { CurrentUser, CurrentUserPayload } from '../auth/decorators/current-user.decorator';
import { Roles } from '../auth/decorators/roles.decorator';
import { RolesGuard } from '../auth/guards/roles.guard';
import { MeetingsService } from '../meetings/meetings.service';
import { VotingService } from './voting.service';

@Controller('meetings/:meetingId')
@UseGuards(AuthGuard('jwt'))
export class VotingController {
  constructor(
    private readonly votingService: VotingService,
    private readonly meetingsService: MeetingsService,
  ) {}

  @Post('vote/open')
  @UseGuards(RolesGuard)
  @Roles(Role.SECRETARY, Role.PRESIDENT)
  open(
    @Param('meetingId') meetingId: string,
    @Body('topicId') topicId: string,
    @CurrentUser() user: CurrentUserPayload,
  ) {
    return this.votingService.openVote(meetingId, topicId, user.id);
  }

  @Post('vote/close')
  @UseGuards(RolesGuard)
  @Roles(Role.SECRETARY, Role.PRESIDENT)
  close(
    @Param('meetingId') meetingId: string,
    @Body('voteSessionId') voteSessionId: string,
    @CurrentUser() user: CurrentUserPayload,
  ) {
    return this.votingService.closeVote(meetingId, voteSessionId, user.id);
  }

  @Post('vote')
  submit(
    @Param('meetingId') meetingId: string,
    @Body('voteSessionId') voteSessionId: string,
    @Body('choice') choice: 'YES' | 'NO' | 'ABSTAIN',
    @CurrentUser() user: CurrentUserPayload,
  ) {
    return this.votingService.submitVote(meetingId, voteSessionId, user.id, choice);
  }

  @Get('vote/current')
  getCurrent(@Param('meetingId') meetingId: string, @CurrentUser() user: CurrentUserPayload) {
    return this.votingService.getOpenSession(meetingId);
  }

  @Get('vote/:voteSessionId/result')
  getResult(
    @Param('meetingId') meetingId: string,
    @Param('voteSessionId') voteSessionId: string,
    @CurrentUser() user: CurrentUserPayload,
  ) {
    return this.votingService.getResult(voteSessionId);
  }

  @Get('vote/:voteSessionId/detailed')
  @UseGuards(RolesGuard)
  @Roles(Role.SECRETARY, Role.PRESIDENT)
  getDetailed(
    @Param('meetingId') meetingId: string,
    @Param('voteSessionId') voteSessionId: string,
  ) {
    return this.votingService.getDetailedResult(voteSessionId);
  }
}
